const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

const SECRET_KEY = process.env.SECRET_KEY || crypto.randomBytes(32).toString('hex');
const HMAC_ALGORITHM = 'sha256';

const users = new Map();
const levelConfigs = new Map([
  [1, { minScore: 0, maxScore: 1000, maxTime: 300, rewards: { coins: 100, gems: 10 } }],
  [2, { minScore: 0, maxScore: 1500, maxTime: 400, rewards: { coins: 150, gems: 15 } }],
  [3, { minScore: 0, maxScore: 2000, maxTime: 500, rewards: { coins: 200, gems: 20 } }]
]);

function generateToken(userId) {
  const timestamp = Date.now();
  const payload = `${userId}:${timestamp}`;
  const signature = crypto.createHmac(HMAC_ALGORITHM, SECRET_KEY)
    .update(payload)
    .digest('hex');
  return Buffer.from(`${payload}:${signature}`).toString('base64');
}

function verifyToken(token) {
  try {
    const decoded = Buffer.from(token, 'base64').toString('utf8');
    const [userId, timestamp, signature] = decoded.split(':');
    
    const payload = `${userId}:${timestamp}`;
    const expectedSignature = crypto.createHmac(HMAC_ALGORITHM, SECRET_KEY)
      .update(payload)
      .digest('hex');
    
    if (signature !== expectedSignature) {
      return null;
    }
    
    if (Date.now() - parseInt(timestamp) > 24 * 60 * 60 * 1000) {
      return null;
    }
    
    return userId;
  } catch (e) {
    return null;
  }
}

function generateLevelHash(userId, levelId, timestamp) {
  const data = `${userId}:${levelId}:${timestamp}`;
  return crypto.createHmac(HMAC_ALGORITHM, SECRET_KEY)
    .update(data)
    .digest('hex');
}

function verifyLevelHash(userId, levelId, timestamp, hash) {
  const expectedHash = generateLevelHash(userId, levelId, timestamp);
  return crypto.timingSafeEqual(
    Buffer.from(hash, 'hex'),
    Buffer.from(expectedHash, 'hex')
  );
}

function authMiddleware(req, res, next) {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  const token = authHeader.substring(7);
  const userId = verifyToken(token);
  
  if (!userId) {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
  
  req.userId = userId;
  next();
}

function validateInput(data, schema) {
  for (const [key, validator] of Object.entries(schema)) {
    if (validator.required && !(key in data)) {
      return `Missing required field: ${key}`;
    }
    
    if (key in data) {
      const value = data[key];
      
      if (validator.type && typeof value !== validator.type) {
        return `Invalid type for ${key}: expected ${validator.type}`;
      }
      
      if (validator.min !== undefined && value < validator.min) {
        return `${key} must be at least ${validator.min}`;
      }
      
      if (validator.max !== undefined && value > validator.max) {
        return `${key} must be at most ${validator.max}`;
      }
      
      if (validator.pattern && !validator.pattern.test(value)) {
        return `Invalid format for ${key}`;
      }
    }
  }
  
  return null;
}

app.post('/api/auth/login', (req, res) => {
  const schema = {
    userId: { required: true, type: 'string', pattern: /^[a-zA-Z0-9_-]{3,32}$/ }
  };
  
  const error = validateInput(req.body, schema);
  if (error) {
    return res.status(400).json({ error });
  }
  
  const { userId } = req.body;
  
  if (!users.has(userId)) {
    users.set(userId, {
      userId,
      coins: 0,
      gems: 0,
      completedLevels: new Set(),
      levelAttempts: new Map(),
      lastActivity: Date.now()
    });
  }
  
  const token = generateToken(userId);
  
  res.json({ token, userId });
});

app.post('/api/level/start', authMiddleware, (req, res) => {
  const schema = {
    levelId: { required: true, type: 'number', min: 1 }
  };
  
  const error = validateInput(req.body, schema);
  if (error) {
    return res.status(400).json({ error });
  }
  
  const { levelId } = req.body;
  const userId = req.userId;
  
  if (!levelConfigs.has(levelId)) {
    return res.status(404).json({ error: 'Level not found' });
  }
  
  const user = users.get(userId);
  const timestamp = Date.now();
  const sessionHash = generateLevelHash(userId, levelId, timestamp);
  
  const attempts = user.levelAttempts.get(levelId) || [];
  attempts.push({ timestamp, sessionHash, completed: false });
  user.levelAttempts.set(levelId, attempts);
  
  res.json({
    levelId,
    timestamp,
    sessionHash,
    config: levelConfigs.get(levelId)
  });
});

app.post('/api/level/complete', authMiddleware, (req, res) => {
  const schema = {
    levelId: { required: true, type: 'number', min: 1 },
    score: { required: true, type: 'number', min: 0 },
    time: { required: true, type: 'number', min: 0 },
    timestamp: { required: true, type: 'number', min: 0 },
    sessionHash: { required: true, type: 'string', pattern: /^[a-f0-9]{64}$/ }
  };
  
  const error = validateInput(req.body, schema);
  if (error) {
    return res.status(400).json({ error });
  }
  
  const { levelId, score, time, timestamp, sessionHash } = req.body;
  const userId = req.userId;
  
  if (!levelConfigs.has(levelId)) {
    return res.status(404).json({ error: 'Level not found' });
  }
  
  const user = users.get(userId);
  const levelConfig = levelConfigs.get(levelId);
  
  const attempts = user.levelAttempts.get(levelId) || [];
  const validAttempt = attempts.find(a => 
    a.timestamp === timestamp && 
    a.sessionHash === sessionHash &&
    !a.completed
  );
  
  if (!validAttempt) {
    return res.status(400).json({ error: 'Invalid or expired session' });
  }
  
  if (!verifyLevelHash(userId, levelId, timestamp, sessionHash)) {
    return res.status(400).json({ error: 'Invalid session hash' });
  }
  
  const timeSinceStart = Date.now() - timestamp;
  if (timeSinceStart < 1000) {
    return res.status(400).json({ error: 'Level completed too quickly' });
  }
  
  if (timeSinceStart > levelConfig.maxTime * 2000) {
    return res.status(400).json({ error: 'Session expired' });
  }
  
  if (score < levelConfig.minScore || score > levelConfig.maxScore) {
    return res.status(400).json({ error: 'Invalid score' });
  }
  
  if (time < 0 || time > levelConfig.maxTime) {
    return res.status(400).json({ error: 'Invalid time' });
  }
  
  validAttempt.completed = true;
  user.completedLevels.add(levelId);
  user.lastActivity = Date.now();
  
  res.json({
    success: true,
    levelId,
    message: 'Level completed successfully'
  });
});

app.post('/api/rewards/claim', authMiddleware, (req, res) => {
  const schema = {
    levelId: { required: true, type: 'number', min: 1 }
  };
  
  const error = validateInput(req.body, schema);
  if (error) {
    return res.status(400).json({ error });
  }
  
  const { levelId } = req.body;
  const userId = req.userId;
  
  if (!levelConfigs.has(levelId)) {
    return res.status(404).json({ error: 'Level not found' });
  }
  
  const user = users.get(userId);
  
  if (!user.completedLevels.has(levelId)) {
    return res.status(400).json({ error: 'Level not completed' });
  }
  
  const attempts = user.levelAttempts.get(levelId) || [];
  const completedAttempts = attempts.filter(a => a.completed);
  
  if (completedAttempts.length === 0) {
    return res.status(400).json({ error: 'No valid completion found' });
  }
  
  const lastCompletion = completedAttempts[completedAttempts.length - 1];
  if (lastCompletion.rewardClaimed) {
    return res.status(400).json({ error: 'Rewards already claimed' });
  }
  
  const levelConfig = levelConfigs.get(levelId);
  const rewards = levelConfig.rewards;
  
  user.coins += rewards.coins;
  user.gems += rewards.gems;
  lastCompletion.rewardClaimed = true;
  
  res.json({
    success: true,
    rewards,
    totalCoins: user.coins,
    totalGems: user.gems
  });
});

app.get('/api/user/profile', authMiddleware, (req, res) => {
  const userId = req.userId;
  const user = users.get(userId);
  
  res.json({
    userId: user.userId,
    coins: user.coins,
    gems: user.gems,
    completedLevels: Array.from(user.completedLevels),
    totalLevels: levelConfigs.size
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});